------------------------------------------------------------commit d7a2c8337f7b615763d4429ab27653862756b6fbDate: Tue Jan 24 18:17:10 2017 +0000...-while (v &gt; smtp_cmd_data &amp;&amp; *v != &#39;=&#39; &amp;&amp; !isspace(*v)) v--;+while (v &gt; smtp_cmd_data &amp;&amp; *v != &#39;=&#39; &amp;&amp; !isspace(*v))+ {+ /* Take care to not stop at a space embedded in a quoted local-part */++ if (*v == &#39;&#34;&#39;) do v--; while (*v != &#39;&#34;&#39; &amp;&amp; v &gt; smtp_cmd_data+1);+ v--;+ }------------------------------------------------------------------------========================================================================CVE-2020-28026: Line truncation and injection in spool_read_header()========================================================================spool_read_header() calls fgets() to read the lines from a spool headerfile into the 16KB big_buffer. The first section of spool_read_header()enlarges big_buffer dynamically if fgets() truncates a line (if a lineis longer than 16KB):------------------------------------------------------------------------ 460 if (Ufgets(big_buffer, big_buffer_size, fp) == NULL) goto SPOOL_READ_ERROR; ... 462 while ( (len = Ustrlen(big_buffer)) == big_buffer_size-1 463 &amp;&amp; big_buffer[len-1] != &#39;
